@Test public void testByAttributeRegexWithPipeInChildCombinator() {
    Document doc = Jsoup.parse("<div><span class='foo'>Child</span></div>");
    Elements els = doc.select("div > [class~=foo|bar]");
    assertEquals(1, els.size());
    assertEquals("Child", els.text());
}

@Test public void testByAttributeRegexWithPipeInAdjacentSiblingCombinator() {
    Document doc = Jsoup.parse("<div><span class='test'>First</span><p class='abc'>Second</p></div>");
    Elements els = doc.select("[class~=test|other] + [class~=abc|xyz]");
    assertEquals(1, els.size());
    assertEquals("Second", els.text());
}

@Test public void testByAttributeRegexWithPipeInGeneralSiblingCombinator() {
    Document doc = Jsoup.parse("<div><span class='first'>A</span><p>B</p><div class='last'>C</div></div>");
    Elements els = doc.select("[class~=first|second] ~ [class~=last|end]");
    assertEquals(1, els.size());
    assertEquals("C", els.text());
}
